export type Endorsement = {
  name: string
  url?: string
}

export type Position = {
  label: string
  url?: string
}

export type Candidate = {
  name: string
  party: string
  website?: string
  endorsements?: Endorsement[]
  supports?: Position[]
  against?: Position[]
}

export type Debate = {
  label: string
  url: string
}

export type Race = {
  id: string
  title: string
  subtitle?: string
  party?: string
  instruction: string
  candidates: Candidate[]
  debates?: Debate[]
}

export type StateQuestion = {
  id: string
  title: string
  subtitle?: string
  text: string
  choices: string[]
}

export type BallotSection = {
  id: string
  heading: string
  races?: Race[]
  questions?: StateQuestion[]
}

export type BallotInfo = {
  title: string
  electionType: string
  additionalType?: string
  date: string
  county: string
  precincts?: string[]
  party?: string
}

export type JurisdictionBallot = {
  county: string
  sections: BallotSection[]
}

